javaBoot.envProfilesApplicationYml:
server:
  port: ${{{port_env}:{port_default}}}

spring:
  application:
    name: {app_name}
  config:
    import: optional:classpath:application-custom.yml
  profiles:
    default: {default_profile}

javaBoot.envProfileSecretsBlock:
ai:
  google:
    genai:
      api-key: ${{GEMINI_API_KEY}}
  elevenlabs:
    api-key: ${{ELEVENLABS_API_KEY:}}
cloud:
  gcp:
    project-id: ${{GCP_PROJECT_ID:}}
    credentials:
      location: ${{GCP_CREDENTIALS:classpath:service-account-key.json}}

javaBoot.hybridEnvYml:
spring:
  datasource:
    url: ${{SPRING_DATASOURCE_URL:jdbc:postgresql://127.0.0.1:5432/{postgres_db}?currentSchema={postgres_schema}}}
    username: ${{POSTGRES_USER:geostat}}
    password: ${{POSTGRES_PASSWORD:geostat-dev-change-me}}
    driver-class-name: org.postgresql.Driver

javaBoot.dockerEnvYml:
spring:
  datasource:
    url: ${{SPRING_DATASOURCE_URL:jdbc:postgresql://postgres:5432/{postgres_db}?currentSchema={postgres_schema}}}
    username: ${{POSTGRES_USER:geostat}}
    password: ${{POSTGRES_PASSWORD:geostat-dev-change-me}}
    driver-class-name: org.postgresql.Driver
{rabbitmq_docker_block}
